{"path": "/tmp/sv-4a83cd1595f646f1b68ab892f66a766a/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "<nav class="catalog-pagination" aria-label="Pagination">
    <button class="page-btn"
            disabled="@(CurrentPage <= 1)"
            @onclick="@(() => ChangePage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNum = i;
        <button class="page-btn @(pageNum == CurrentPage ? "active" : "")"
                @onclick="@(() => ChangePage(pageNum))">
            @pageNum
        </button>
    }

    <button class="page-btn"
            disabled="@(CurrentPage >= TotalPages)"
            @onclick="@(() => ChangePage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; } = 1;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task ChangePage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

