.catalog-filters {
    padding: 1.5rem;
    border-right: 1px solid #e0e0e0;
    height: 100%;
}

.catalog-filters h2 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
}

.filter-section {
    margin-bottom: 1.5rem;
}

.filter-section h3 {
    margin: 0 0 0.5rem;
    font-size: 0.95rem;
    font-weight: 600;
}

.checkbox-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.25rem 0;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.85rem;
}

.price-inputs input {
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply {
    padding: 0.5rem 1rem;
    background: #2d6a4f;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 600;
}

.btn-apply:hover {
    background: #1b4332;
}

.btn-clear {
    padding: 0.5rem 1rem;
    background: transparent;
    color: #666;
    border: 1px solid #ccc;
    border-radius: 4px;
    cursor: pointer;
}

.btn-clear:hover {
    background: #f5f5f5;
}

